import React from 'react';
import $ from 'jquery';

class Searchbutton extends React.Component {
    render() {
        const request =  new XMLHttpRequest();

        const getrequest = () => {
        const artist = document.getElementById('artist');
        const title = document.getElementById('title');
        var appbody = document.getElementById('lyricsbody');
        $('#lyricsbody').delay(1000).slideDown(1000);
        appbody.innerHTML = 'Loading...';
        
            request.open('GET', 'https://api.lyrics.ovh/v1/' + artist.value + '/' + title.value + "'")
            request.onreadystatechange = function () {
                if (this.readyState === 4 && this.status === 200) {
                
                const responseObject = JSON.parse(this.responseText);
                $('#lyricsbody').delay(1000).slideDown(1000);
                appbody.innerHTML = title.value.toUpperCase() + ' by ' + artist.value.toLowerCase();
                appbody.innerHTML += '<p>' + responseObject.lyrics + '</p>';
                } else {
                const appbody = document.getElementById('lyricsbody');
                const responseObject = JSON.parse(this.responseText);
                $('#intro').slideUp(500);
                $('#body').delay(1000).slideDown(1000);
                appbody.innerHTML = "Oops!!! " + responseObject.error;
                }
            }
         
          request.send() 
        }
        
        const checkInput = () => {
            const artist = document.getElementById('artist');
            const title = document.getElementById('title');
            if (artist.value === '' && title.value === '') {
                artist.style.borderColor = 'red';
                title.style.borderColor = 'red';
            } else if (artist.value === '' && title.value !== '') {
                artist.style.borderColor = 'red';
                title.style.borderColor = 'unset';
            } else if (artist.value !== '' && title.value === '') {
                title.style.borderColor = 'red';
                artist.style.borderColor = 'unset';
            } else {
                getrequest();
            }
        }
        return(
            <button type="submit" onClick={checkInput}>Search</button>
        )
    }
}

export default Searchbutton;